  ('real-estate-moex-01114', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲向乙承租A地種植柚子樹，後來政府公告將徵收A地。下列敘述何者錯誤？', '["柚子樹為不動產之出產物，屬於乙所有", "柚子為天然孳息，天然孳息的收取權為土地所有權人乙", "政府徵收乙所有的A地，範圍包括甲在A地上種植的柚子樹", "政府徵收A地之補償金歸屬於乙"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01115', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', 'A公司的董事甲前往與客戶簽約時，不慎撞傷路人乙。下列敘述何者正確？', '["屬車禍事故，由董事甲自行負損害賠償責任", "由A公司負損害賠償責任，但是A公司對董事甲有求償權", "由A公司與董事甲連帶負損害賠償責任", "A公司若已盡監督職務執行之責，可舉證免責"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01116', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '某甲25歲，為受輔助宣告之人。下列敘述何者正確？', '["甲之輔助宣告可由其表哥向社會福利機構提出聲請", "甲受輔助宣告後，自行購買不動產的行為，無效", "甲之輔助人乙，不得受讓甲所有的A屋", "甲受輔助宣告後，自行將其所有的智慧型手機贈與好友丙的行為，有效"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01117', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲所有的古董花瓶為乙所盜並寄放在丙的古董店裡展售，嗣後為顧客丁所買。關於當事人之間的權 利義務，下列敘述何者錯誤？', '["丙出售古董花瓶的行為，須經甲的承認始生效力", "不知情的顧客丁因丙的受讓移轉，取得古董花瓶的所有權", "該古董花瓶係盜贓物，甲得於古董花瓶喪失占有之時起一年內向丁請求回復其物", "甲須償還丁購買古董花瓶之價金，始得請求回復其物"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01118', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲向乙購買房屋，雙方簽訂買賣契約後，乙將房屋交付於甲，但尚未辦理所有權移轉登記，突然發 生地震致使房屋全毀。下列敘述何者正確？', '["甲雖未取得房屋所有權，但仍需交付約定之房屋價金", "甲因未取得房屋所有權，故毋需交付約定之房屋價金", "甲已受領房屋之交付，故需交付約定之房屋價金之一半", "甲已受領房屋之交付，僅需給付相當於使用房屋之租金"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01119', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲所有的A地因通行之需在乙的B地上設定不動產役權。下列敘述何者錯誤？', '["甲得將A地設定抵押權與丙銀行", "甲得將B地上的不動產役權單獨讓與給丁", "嗣後A地分割並讓與，為戊、己所有，戊、己皆享有B地上的不動產役權", "嗣後B地分割並讓與，為庚、辛所有，甲的不動產役權仍存在庚、辛受讓的B地上"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01120', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲向乙承租房屋居住，因火災致房屋毀損滅失，乙請求甲損害賠償。下列敘述何者正確？', '["甲因火災致乙之房屋毀損滅失，構成侵權行為，應負抽象輕過失責任", "甲因火災致乙之房屋毀損滅失，構成侵權行為，應負具體輕過失責任", "甲因火災致乙之房屋毀損滅失，承租人甲僅負重大過失責任", "甲因火災致乙之房屋毀損滅失，承租人甲僅負故意責任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01121', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲早年喪偶，育有子女三人乙、丙、丁，嗣後與戊女結婚，並生有二子女A、B，戊女與前夫育有二女 C、D。關於這家人將來的繼承關係，下列敘述何者正確？', '["若甲死亡，甲的遺產由乙、丙、丁、戊及A、B、C、D共同繼承", "若戊死亡，戊的遺產由甲和A、B、C、D共同繼承", "若乙未婚，因意外事故死亡，乙的遺產由甲、戊共同繼承", "若戊與C出遊，二人因意外事故死亡，C未婚，C的遺產由甲與D共同繼承"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01122', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲男乙女為夫妻，乙生下孩子丙。下列關於受胎期間之推定何者錯誤？', '["甲乙於民國100年2月1日結婚，丙於同年7月1日出生，丙為甲乙在婚姻關係存續中所生的孩 子，丙推定為甲乙的婚生子女", "甲乙於民國100年2月1日結婚，丙於同年12月1日出生，丙為甲乙在婚姻關係存續中所生的孩 子，丙推定為甲乙的婚生子女", "甲乙於民國100年3月1日離婚，丙於同年7月1日出生，丙雖非甲乙在婚姻關係存續中所生的孩 子，但丙推定為甲乙的婚生子女", "甲乙於民國100年3月1日離婚，丙於同年11月1日出生，丙雖非甲乙在婚姻關係存續中所生的孩 子，但丙推定為甲乙的婚生子女"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01123', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '趙男與錢女結婚，婚後產下一子登記姓名為趙大富。下列敘述何者錯誤？', '["趙大富未成年前，得由父母以書面約定變更為錢大富", "嗣後趙男與錢女離婚，法院得依錢女之請求，為子女之利益，宣告變更趙大富為錢大富", "趙大富20歲後，經父母同意得申請變更姓氏為錢大富", "已成年子女姓氏的變更其次數以一次為限"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
